mapper.update:
update user
openid = #{openid}, name = #{name}, phone = #{phone}, password = #{password}, sex = #{sex}, id_number = #{idNumber}, avatar = #{avatar}
where id = #{id}

mapper.select:
select id, openid, name, phone, password, sex, id_number as idNumber, avatar, create_time as createTime
from user
where id = #{id}

select id, openid, name, phone, sex, id_number as idNumber, avatar, create_time as createTime from user
and name like concat('%', #{name}, '%') and phone like concat('%', #{phone}, '%')
order by id desc limit #{page}, #{pageSize}
